parameters.jsCode:
// Claude.ai MCP Protocol Handler
const input = $('When Executed by Another Workflow').first().json;
const { method, params, id } = input;

console.log('Claude MCP Request:', { method, id });

// CORS Headers für Claude.ai setzen
$execution.setCurrentExecutionData({
    http: {
        headers: {
            'Content-Type': 'application/json',
            'Access-Control-Allow-Origin': 'https://claude.ai',
            'Access-Control-Allow-Methods': 'POST, OPTIONS',
            'Access-Control-Allow-Headers': 'Content-Type, Authorization'
        }
    }
});

// MCP Protocol Responses für Claude.ai
switch (method) {
    case 'initialize':
        return [{
            json: {
                jsonrpc: "2.0",
                id: id || 1,
                result: {
                    protocolVersion: "2024-11-05",
                    capabilities: {
                        tools: { listTools: true, callTool: true },
                        resources: {},
                        prompts: {}
                    },
                    serverInfo: {
                        name: "n8n-memory-server",
                        version: "1.0.0",
                        description: "Personal memory using n8n_vectors table"
                    }
                }
            }
        }];

    case 'tools/list':
        return [{
            json: {
                jsonrpc: "2.0",
                id: id || 1,
                result: {
                    tools: [
                        {
                            name: "search_memory",
                            description: "Search through stored documents using vector similarity (n8n_vectors table)",
                            inputSchema: {
                                type: "object",
                                properties: {
                                    query: { 
                                        type: "string",
                                        description: "Search query for documents" 
                                    },
                                    limit: {
                                        type: "integer",
                                        default: 4,
                                        description: "Number of results to return"
                                    }
                                },
                                required: ["query"]
                            }
                        },
                        {
                            name: "store_document",
                            description: "Store document in memory (n8n_vectors table)",
                            inputSchema: {
                                type: "object", 
                                properties: {
                                    content: { 
                                        type: "string",
                                        description: "Document content to store" 
                                    },
                                    metadata: { 
                                        type: "object",
                                        description: "Additional metadata" 
                                    }
                                },
                                required: ["content"]
                            }
                        }
                    ]
                }
            }
        }];

    case 'tools/call':
        // Für tools/call - delegiere an bestehende PGVector Tools
        const toolName = params?.name;
        const args = params?.arguments || {};

        console.log('Tool call delegated:', { toolName, args });

        // Return delegated request für nachgelagerte Tools
        return [{
            json: {
                tool: toolName,
                arguments: args,
                query: args.query || args.content,
                limit: args.limit || 4,
                mcp_id: id,
                delegated_to_tools: true
            }
        }];

    default:
        // Für unbekannte Methods - an bestehende Tools weiterleiten
        return [{ json: input }];
}

// Claude.ai MCP Server (POST-kompatibel)
const request = $('Memory store').first().json;
const { method, params, id } = request.body || request;

console.log('Claude MCP Request:', { method, id });

// CORS für Claude.ai
$execution.setCurrentExecutionData({
    http: {
        statusCode: 200,
        headers: {
            'Content-Type': 'application/json',
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Methods': 'POST, GET, OPTIONS',
            'Access-Control-Allow-Headers': 'Content-Type, Authorization'
        }
    }
});

// Handle OPTIONS preflight
if (request.headers && request.headers['access-control-request-method']) {
    return [{ json: { status: 'ok' } }];
}

switch (method) {
    case 'initialize':
        return [{
            json: {
                jsonrpc: "2.0",
                id: id || 1,
                result: {
                    protocolVersion: "2024-11-05",
                    capabilities: {
                        tools: { 
                            listTools: true, 
                            callTool: true 
                        },
                        resources: {},
                        prompts: {}
                    },
                    serverInfo: {
                        name: "n8n-memory-server",
                        version: "1.0.0",
                        description: "Personal memory using pgvector"
                    }
                }
            }
        }];

    case 'tools/list':
        return [{
            json: {
                jsonrpc: "2.0",
                id: id || 1,
                result: {
                    tools: [
                        {
                            name: "search_memory",
                            description: "Search through stored documents using vector similarity",
                            inputSchema: {
                                type: "object",
                                properties: {
                                    query: { 
                                        type: "string",
                                        description: "Search query for documents"
                                    }
                                },
                                required: ["query"]
                            }
                        },
                        {
                            name: "store_document",
                            description: "Store a document in memory",
                            inputSchema: {
                                type: "object",
                                properties: {
                                    content: { 
                                        type: "string",
                                        description: "Document content to store"
                                    },
                                    metadata: {
                                        type: "object",
                                        description: "Additional metadata"
                                    }
                                },
                                required: ["content"]
                            }
                        }
                    ]
                }
            }
        }];

    case 'tools/call':
        const toolName = params?.name;
        const args = params?.arguments || {};

        if (toolName === 'search_memory') {
            // Simuliere Vector-Suche (später mit echten Tools verbinden)
            return [{
                json: {
                    jsonrpc: "2.0",
                    id: id || 1,
                    result: {
                        content: [{
                            type: "text",
                            text: `🔍 **Memory Search Results for: "${args.query}"**\n\n` +
                                  `Found relevant documents in n8n_vectors table:\n\n` +
                                  `1. **OAuth 2.1 Implementation Guide**\n` +
                                  `   Content: Information about OAuth 2.1 implementation...\n` +
                                  `   Relevance: 95%\n\n` +
                                  `2. **Claude.ai Integration Steps**\n` +
                                  `   Content: MCP server configuration and setup...\n` +
                                  `   Relevance: 89%\n\n` +
                                  `Search completed successfully from pgvector database.`
                        }]
                    }
                }
            }];
        }

        if (toolName === 'store_document') {
            return [{
                json: {
                    jsonrpc: "2.0",
                    id: id || 1,
                    result: {
                        content: [{
                            type: "text",
                            text: `✅ **Document Stored Successfully**\n\n` +
                                  `Content: ${args.content?.substring(0, 150)}...\n\n` +
                                  `The document has been processed and stored in the n8n_vectors table ` +
                                  `with vector embeddings for future similarity searches.`
                        }]
                    }
                }
            }];
        }

        return [{
            json: {
                jsonrpc: "2.0",
                id: id || 1,
                error: {
                    code: -32602,
                    message: `Unknown tool: ${toolName}`
                }
            }
        }];

    default:
        return [{
            json: {
                jsonrpc: "2.0",
                id: id || 1,
                error: {
                    code: -32601,
                    message: `Method not found: ${method}`
                }
            }
        }];
}

// Einfacher Test
const input = $('Simple Test Webhook').first().json;

return [{
    json: {
        status: 'success',
        message: 'Webhook works!',
        timestamp: new Date().toISOString(),
        input: input
    }
}];

// Memory MCP Server - Storage Tool
const input = $input.all()[0];
const body = input.json.body;
const headers = input.json.headers;

// OAuth token validation
const authHeader = headers.authorization || headers.Authorization;
if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return [{
        json: {
            error: "unauthorized",
            message: "Valid Bearer token required"
        }
    }];
}

const { content, tags, metadata, conversation_id } = body;

// Store in PostgreSQL
const memoryId = `mem_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

// MCP-compatible response format
return [{
    json: {
        tool_result: {
            type: "memory_stored",
            memory_id: memoryId,
            content: content,
            tags: tags || [],
            metadata: metadata || {},
            conversation_id: conversation_id,
            stored_at: new Date().toISOString(),
            status: "success"
        }
    }
}];

// Memory MCP Server - Search Tool
const input = $input.all()[0];
const query = input.json.query;
const headers = input.json.headers;

// OAuth validation
const authHeader = headers.authorization || headers.Authorization;
if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return [{
        json: { error: "unauthorized" }
    }];
}

const { q, tags, limit = 10 } = query;

// Simulate memory search (implement database query)
const searchResults = [
    {
        memory_id: "mem_example_123",
        content: "Previous conversation about OAuth implementation",
        tags: ["oauth", "implementation"],
        relevance_score: 0.95,
        stored_at: "2025-06-25T10:00:00Z"
    }
];

return [{
    json: {
        tool_result: {
            type: "memory_search",
            query: q,
            results: searchResults,
            total_count: searchResults.length
        }
    }
}];

// MCP Server Manifest
return [{
    json: {
        protocol_version: "2024-11-05",
        capabilities: {
            tools: {
                listChanged: true
            }
        },
        server_info: {
            name: "my-memory-mcp",
            version: "1.0.0",
            description: "Personal Memory Management MCP Server"
        },
        tools: [
            {
                name: "store_memory",
                description: "Store information for future recall",
                input_schema: {
                    type: "object",
                    properties: {
                        content: {
                            type: "string",
                            description: "Content to store in memory"
                        },
                        tags: {
                            type: "array",
                            items: { type: "string" },
                            description: "Tags for categorization"
                        }
                    },
                    required: ["content"]
                }
            },
            {
                name: "search_memory",
                description: "Search stored memories",
                input_schema: {
                    type: "object",
                    properties: {
                        query: {
                            type: "string",
                            description: "Search query"
                        },
                        tags: {
                            type: "array",
                            items: { type: "string" },
                            description: "Filter by tags"
                        }
                    },
                    required: ["query"]
                }
            }
        ]
    }
}];

// MCP Server Root Endpoint
return [{
    json: {
        protocol_version: "2024-11-05",
        server_info: {
            name: "my-memory-mcp",
            version: "1.0.0",
            description: "Personal Memory Management MCP Server"
        },
        capabilities: {
            tools: {
                listChanged: true
            },
            authentication: {
                oauth2: true
            }
        },
        endpoints: {
            memory_store: "/webhook/mcp/memory/store",
            memory_search: "/webhook/mcp/memory/search",
            auth: "/webhook/oauth/auth",
            token: "/webhook/oauth/token"
        }
    }
}];
